const d = $input.first().json;
const now = new Date();
const citaFecha = d.fechaTimestamp ? new Date(d.fechaTimestamp) : new Date();
const diffMs = citaFecha - now;
const diffHoras = diffMs / (1000 * 60 * 60);
const esperarMs = diffHoras > 24
  ? diffMs - 24 * 60 * 60 * 1000
  : Math.max(0, diffMs - 2 * 60 * 60 * 1000);
const esMenos24h = diffHoras <= 24;
return [{ json: { ...d, esperarMs: Math.max(0, esperarMs), esMenos24h } }];

const d = $input.first().json;
const esMenor = d.esMenor || false;
const telefonoDestino = d.telefonoTutor || d.telefono;
const linkCuestionario = `${$vars.CUESTIONARIO_BASE_URL}?token=${d.token || d.idPac}`;
const cuando = d.esMenos24h ? 'hoy' : 'mañana';
const texto = esMenor
  ? `👶 Hola ${d.nombreTutor || d.nombre}, ${cuando} es la primera cita de *${d.nombre}* a las ${d.horaStr}h.

Completa los documentos antes de la visita (5 min):
📋 Cuestionario de salud + LOPD: ${linkCuestionario}

⏰ El enlace expira 1h después de la cita.`
  : `👋 Hola ${d.nombre}, ${cuando} tienes tu primera cita en ${$vars.CLINICA_NOMBRE} a las *${d.horaStr}h*.

Para prepararla completa estos documentos (3 min):
📋 Cuestionario de salud: ${linkCuestionario}
🔒 Incluye firma de privacidad (LOPD)

⏰ El enlace expira 1h después de tu cita.`;
return [{ json: { ...d, mensaje: texto, telefonoDestino, linkCuestionario } }];
